    "0035e319": {"text":"Imam","hash":"h1-1dcd3835"},
    "0036af5c": {"text":"🕯 {province} betrügt die Krone – ihr Herr starb ohne Erben.","hash":"h1-f1de26d8"},
    "0036bb8b": {"text":"Der Förster findet Sie jenseits der neuen Pfähle und meldet den Verstoß.","hash":"h1-f38d322e"},
    "0049d8d1": {"text":"Eigentümer","hash":"h1-1000b579"},
    "00534d08": {"text":"Tochter des Kaufmanns","hash":"h1-82f7f49b"},
    "00655004": {"text":"🕸 Eine Handlung wird in Gang gesetzt: {plot}.","hash":"h1-cd3a0a05"},
    "006a5b06": {"text":"💍 Deine Schwester {name} heiratet {spouse}.","hash":"h1-539d0415"},
    "0073e4a6": {"text":"Verdoppeln Sie die Wache, belohnen Sie die Treuen. (15 Gold)","hash":"h1-e126667c"},
