    "28285cf0": {"text":"Sammeln Sie im Dunkeln, wer Sie können.","hash":"h1-b3ac70e8"},
    "2828f232": {"text":"Ringen Sie um die Ehre des Lagers.","hash":"h1-94ef7bfe"},
