    "2865a2bb": {"text":"Tengrismus","hash":"h1-7b8ca658"},
    "28663830": {"text":"Großartig {temple}","hash":"h1-d4975bd6"},
    "288f1e56": {"text":"Lass die Liebe hartnäckig sein.","hash":"h1-6b8f6498"},
    "28996151": {"text":"Millers Tochter","hash":"h1-6fca9c04"},
    "28b6fc34": {"text":"Übernehmen Sie eine Innovation","hash":"h1-a9f7dd47"},
    "28e101f1": {"text":"Niedergeschlagen durch einen Aufstand des Gemeinwesens.","hash":"h1-4443aea4"},
    "2913c1e6": {"text":"Verteidigen Sie das Recht der Witwe, den Handel abzuschließen.","hash":"h1-9b0e1ac3"},
    "292156e3": {"text":"Die Pest endete.","hash":"h1-019a28c4"},
    "2938ca8a": {"text":"Laufen Sie, um weitere Hilfe zu erhalten.","hash":"h1-27a7ad79"},
    "29486d20": {"text":"Halte es aus.","hash":"h1-51677669"},
    "2951d816": {"text":"Ertragen Sie das Urteil und denken Sie daran.","hash":"h1-17ff4a53"},
