    "29bc1e39": {"text":"Noch nicht. Sparen Sie zuerst mehr.","hash":"h1-bd46e2b4"},
    "29c60ddf": {"text":"({days} Tage Weben, ungefähr)","hash":"h1-52c8b451"},
    "29e00e5a": {"text":"Frage folgt auf Frage; Der Wortlaut ändert sich nie. Das Testament steht.","hash":"h1-579ad719"},
