    "2a53ba31": {"text":"Kaufte einen freistehenden Bauernhof.","hash":"h1-20f61a1e"},
    "2a85c036": {"text":"Kommandiere deine Männer im Feld. (bessere Chancen beim Kriegsrat)","hash":"h1-0b814e4f"},
    "2a8c439b": {"text":"Du schwitzt bei deiner Arbeit.","hash":"h1-380b5786"},
    "2acb1b68": {"text":"🕯 Ihr Sohn {name} ist im Alter von {age} gestorben.","hash":"h1-25cd9da1"},
    "2aec7e7c": {"text":"Die Beleidigung fällt ins Leere. {name} antwortet besser und das Lachen gehört ihnen.","hash":"h1-8aad326c"},
    "2af3cf20": {"text":"Du hast {spouse} geheiratet, nicht das ganze Haus.","hash":"h1-5750a399"},
    "2b13a5f0": {"text":"Verkaufe Bier an die Fröhlichen.","hash":"h1-0e4fdf99"},
    "2b281d2c": {"text":"Drücken Sie die Belagerung von {target}.","hash":"h1-d884cf45"},
    "2b2ba791": {"text":"Ein langsamer Markttag. Sie legen kaum die Straße zurück.","hash":"h1-9c72947d"},
    "2b4de4bf": {"text":"Du bist {name}, ein Speer im Dienste des Herrn von {province}. Die Löhne sind gering, aber auf Schlachtfeldern wird niemand zu jemandem.","hash":"h1-b85a5380"},
    "2b4e6d33": {"text":"– Ihr Vasall","hash":"h1-706205dc"},
    "2b5cc1bd": {"text":"Die Kindheit ist kurz. Verbringen Sie es gut.","hash":"h1-606fdf42"},
    "2b69beae": {"text":"Damaszenerklinge","hash":"h1-5ab70862"},
    "2b9e68d2": {"text":"🚩 Von hier aus führt kein Weg zum Host von {enemy}.","hash":"h1-4bb3425b"},
    "2bb04858": {"text":"Düstere Arbeit, heilige Arbeit. Das Dorf wird nicht vergessen.","hash":"h1-7c34ad69"},
    "2bb15ed4": {"text":"Grenzen ziehen…","hash":"h1-db1fa674"},
    "2bb31c22": {"text":"Priester","hash":"h1-f31d6b4e"},
    "2bf2c387": {"text":"Wassergemusterter Stahl aus dem Osten. Es verzeiht nicht.","hash":"h1-4e6911a2"},
    "2c0066e0": {"text":"Stadt","hash":"h1-b35efe12"},
    "2c6a0504": {"text":"🐙 GitHub-Probleme","hash":"h1-71bcd04e"},
    "2c778848": {"text":"Unter diesem Dach kann jemand lesen – und die Kinder lernen früh.","hash":"h1-f002a838"},
    "2cb3b220": {"text":"wechselt zwischen den Schaltflächen.","hash":"h1-2e81cd3a"},
    "2ced2b07": {"text":"⚔ {attacker} kämpft gegen {defender}.","hash":"h1-035d4999"},
    "2d340e86": {"text":"Woran sich die alten Leute erinnern","hash":"h1-1d7adfc4"},
    "2d4282fc": {"text":"Briefe in der Familie","hash":"h1-040c9956"},
    "2d50aa4b": {"text":"Kalif","hash":"h1-1e2cbcca"},
    "2d8ea885": {"text":"Tochter des Hauses des Herrn","hash":"h1-59adfe14"},
    "2db48fa5": {"text":"Wachen stürmten herein; Der Attentäter taucht durch das Fenster in die Nacht.","hash":"h1-d3c60549"},
    "2dbed7eb": {"text":"Ein Herold in den Farben deines Lehnsherrn: Der Krieg wird erklärt und dein Banner wird aufgerufen, dich mit aller Kraft zu mobilisieren.","hash":"h1-1279c6e5"},
    "2dd30133": {"text":"Trainieren Sie stattdessen Ihre Männer.","hash":"h1-bb2c4f9f"},
